    if (!hProcess) {
        std::cerr << "Failed to open process" << std::endl;
        return NULL;
    }

    HANDLE hThread = OpenThread(THREAD_QUERY_INFORMATION | THREAD_SET_CONTEXT, FALSE, threadId);
    if (!hThread) {
